const store = $getWorkflowStaticData('global');
const sessions = store.u || {};
let best = null, bestScore = -1;
for (const [sid, u] of Object.entries(sessions)) {
  const score = (u.tasks?.length||0) + (u.projects?.length||0) + (u.notes?.length||0);
  if (score > bestScore) { bestScore = score; best = u; }
}
if (!best) best = {};

const today = new Date().toISOString().slice(0,10);
const todayRu = new Date().toLocaleDateString('ru',{weekday:'long',day:'numeric',month:'long'});

const pending = (best.tasks||[]).filter(t=>!t.done);
const in7 = new Date(Date.now()+7*86400000).toISOString().slice(0,10);
const events = (best.calendar||[]).filter(e=>e.date>=today&&e.date<=in7).sort((a,b)=>a.date>b.date?1:-1);
const thisMonth = today.slice(0,7);

// Finance: пользовательские записи + транзакции Альфы из backend
const userFin = best.finance || [];
const alfaTxs = $('Fetch Alfa').first().json.txs || [];
const userIn = userFin.filter(e=>e.type==='in' &&e.date?.startsWith(thisMonth)).reduce((s,e)=>s+e.amount,0);
const userOut = userFin.filter(e=>e.type==='out'&&e.date?.startsWith(thisMonth)).reduce((s,e)=>s+e.amount,0);
const alfaIn = alfaTxs.filter(t=>t.direction==='in').reduce((s,t)=>s+(Number(t.amount)||0),0);
const alfaOut = alfaTxs.filter(t=>t.direction!=='in').reduce((s,t)=>s+(Number(t.amount)||0),0);
const finIn = userIn + alfaIn;
const finOut = userOut + alfaOut;
const alfaCount = alfaTxs.length;

// Top-3 категорий трат месяца
const byCat = {};
for (const t of alfaTxs) {
  if (t.direction === 'in') continue;
  const c = t.category || '❓';
  byCat[c] = (byCat[c] || 0) + (Number(t.amount) || 0);
}
const topCats = Object.entries(byCat).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([c,s])=>c+': '+Math.round(s)+' ₽').join(', ');

const ctActive = (best.content||[]).filter(e=>e.status!=='done').length;
const ideasCount = (best.ideas||[]).length;

return [{ json: { todayRu, pending, events, finIn, finOut, alfaCount, topCats, ctActive, ideasCount } }];

const res = $input.first().json;
if (!res.choices) return [{ json: { text: 'Доброе утро, Денис! Зевс на связи 🌅' } }];
return [{ json: { text: res.choices[0].message.content.trim() } }];
